</section>

<!-- LA SENDA DEL CONSULTOR: 3 NIVELES -->
<section class="ji-section ji-section--light">
  <div class="ji-container ji-text-center">
    <div class="ji-section__label">Certification Program</div>
    <h2 class="ji-section__title">The Path of the Impact Consultant</h2>
    <p class="ji-section__subtitle">Three progressive levels that take you from the fundamentals to leadership in digital ecosystem transformation.</p>
    <div class="ji-grid ji-grid--3" style="text-align:left;">
      <div class="ji-level ji-level--1">
        <div class="ji-level__number">1</div>
        <span class="ji-badge ji-badge--secondary">Associate Level</span>
        <h3 class="ji-level__title" style="margin-top:12px;">Master the Fundamentals</h3>
        <p class="ji-level__subtitle">In Digital Ecosystems</p>
