        <ul class="ji-level__list">
          <li>Official Associate Level Certification</li>
          <li>Basic profile on the marketplace</li>
          <li>Access to consultant community</li>
        </ul>
      </div>
      <div class="ji-level ji-level--2">
        <div class="ji-level__number">2</div>
        <span class="ji-badge ji-badge--primary">Certified Level</span>
        <h3 class="ji-level__title" style="margin-top:12px;">Apply the Strategy</h3>
        <p class="ji-level__subtitle">In Digital Strategy</p>
        <div class="ji-level__section-title">Requirements</div>
        <ul class="ji-level__list">
          <li>Associate Level Certification</li>
          <li>Presentation of 1 audited success story</li>
          <li>Advanced training in strategy and management</li>
        </ul>
        <div class="ji-level__section-title">Benefits</div>
        <ul class="ji-level__list">
          <li>"Certified Consultant" badge</li>
          <li>Featured and verified marketplace profile</li>
          <li>Access to pre-qualified leads</li>
        </ul>
      </div>
      <div class="ji-level ji-level--3">
        <div class="ji-level__number">3</div>
        <span class="ji-badge ji-badge--accent">Master Level</span>
        <h3 class="ji-level__title" style="margin-top:12px;">Lead the Transformation</h3>
        <p class="ji-level__subtitle">In Ecosystem Transformation</p>
        <div class="ji-level__section-title">Requirements</div>
        <ul class="ji-level__list">
          <li>Certified Level Certification</li>
